BEGIN TRANSACTION;
CREATE TABLE definitions (
			module TEXT NOT NULL,
			function TEXT NOT NULL DEFAULT '',
			arity INTEGER NOT NULL DEFAULT 0,
			kind TEXT NOT NULL,
			line INTEGER NOT NULL,
			file_path TEXT NOT NULL,
			delegate_to TEXT NOT NULL DEFAULT '',
			delegate_as TEXT NOT NULL DEFAULT '',
			params TEXT NOT NULL DEFAULT '',
			FOREIGN KEY (file_path) REFERENCES files(path) ON DELETE CASCADE
		);
CREATE TABLE files (
			path TEXT PRIMARY KEY,
			mtime INTEGER NOT NULL
		);
CREATE TABLE metadata (
			key   TEXT PRIMARY KEY,
			value TEXT NOT NULL
		);
CREATE TABLE refs (
			module TEXT NOT NULL,
			function TEXT NOT NULL DEFAULT '',
			line INTEGER NOT NULL,
			file_path TEXT NOT NULL,
			kind TEXT NOT NULL DEFAULT 'call',
			FOREIGN KEY (file_path) REFERENCES files(path) ON DELETE CASCADE
		);
CREATE INDEX idx_definitions_module_function ON definitions(module, function);
CREATE INDEX idx_definitions_file_path_line ON definitions(file_path, line);
CREATE INDEX idx_refs_module_function ON refs(module, function);
CREATE INDEX idx_refs_file_path ON refs(file_path);
CREATE INDEX idx_refs_function_kind ON refs(function, kind);
CREATE INDEX idx_definitions_delegate_to ON definitions(delegate_to);
COMMIT;
